const shortPath = (projectPath: string): string => {
  const parts = projectPath.split("/");
  if (parts.length <= 4) return projectPath;
  return `.../${parts.slice(-3).join("/")}`;
};

const runLabel = (status: TicketSummary["runStatus"]): string => {
  switch (status) {
    case "idle":
      return "Idle";
    case "running":
      return "Running";
    case "blocked":
      return "Blocked";
    case "failed":
      return "Failed";
    case "completed":
      return "Codex Done";
    case "cancelled":
      return "Cancelled";
    case "drafting":
      return "Drafting";
    default:
      return "Idle";
  }
};

const eventText = (event: RendererRunEvent): string => {
  switch (event.type) {
    case "run.started":
      return `Run started (${event.threadId})`;
    case "agent.message.delta":
    case "agent.message.completed":
      return event.text;
    case "command.started":
      return `$ ${event.command}`;
    case "command.output":
      return event.text;
    case "command.completed":
      return `Command ${event.status}`;
    case "file.change":
      return event.summary ?? event.path;
    case "approval.requested":
      return `Approval requested: ${event.kind}`;
    case "approval.resolved":
      return `Approval ${event.decision}`;
    case "run.completed":
      return event.finalResponse;
    case "run.failed":
      return event.message;
    default:
      return "";
  }
};

