export const RELAY_SCHEMA_VERSION = 1;

export const DEFAULT_COLUMNS: RelayColumn[] = [
  { id: "todo", name: "Todo", position: 1000, terminal: false },
  { id: "in_progress", name: "In Progress", position: 2000, terminal: false },
  { id: "needs_clarification", name: "Needs Clarification", position: 3000, terminal: false },
  { id: "not_doing", name: "Not Doing", position: 4000, terminal: true },
  { id: "completed", name: "Completed", position: 5000, terminal: true }
];

export type TicketPriority = "low" | "medium" | "high" | "urgent";
export type RunStatus = "idle" | "drafting" | "running" | "blocked" | "failed" | "completed" | "cancelled";
export type ProjectHealth = "ok" | "warning" | "error";
export type ThemePreference = "system" | "light" | "dark";
export type RelayActor = "user" | "codex" | "system";
export type RelayEventSource =
  | "manual_board"
  | "manual_ticket_edit"
  | "agent_execution"
  | "clarification_ui"
  | "system_reconciliation";

export type RelayColumn = {
  id: string;
  name: string;
  position: number;
  terminal: boolean;
};

export type ProjectSettings = {
  defaultModel: string | null;
  defaultApprovalPolicy: "untrusted" | "on-request" | "never";
  defaultSandboxMode: "read-only" | "workspace-write" | "danger-full-access";
  allowNonGitCodexRuns: boolean;
  ticketDraftingEnabled: boolean;
  codexExecutionEnabled: boolean;
};

export type ProjectConfig = {
  schemaVersion: number;
  projectId: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  columns: RelayColumn[];
  settings: ProjectSettings;
};

export type ProjectSummary = {
  projectId: string | null;
  name: string;
  path: string;
  exists: boolean;
  isGitRepository: boolean;
  relayInitialized: boolean;
  health: ProjectHealth;
  healthMessages: string[];
  activeRunCount: number;
  lastOpenedAt?: string;
};

export type TicketFrontMatter = {
  schemaVersion: number;
  id: string;
  title: string;
  status: string;
  position: number;
  priority: TicketPriority;
  labels: string[];
  createdAt: string;
  updatedAt: string;
  codexThreadId: string | null;
  runStatus: RunStatus;
  lastRunId: string | null;
};

export type TicketRecord = {
  frontMatter: TicketFrontMatter;
  markdown: string;
  filePath: string;
};

export type TicketSummary = TicketFrontMatter & {
  excerpt: string;
  filePath: string;
};

export type InvalidTicket = {
  filePath: string;
  reason: string;
};

export type BoardSnapshot = {
  project: ProjectSummary;
  config: ProjectConfig | null;
  columns: RelayColumn[];
  tickets: TicketSummary[];
  invalidTickets: InvalidTicket[];
};

export type TicketDraft = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  context: string;
  requirements: string[];
  acceptanceCriteria: string[];
  clarificationQuestions: string[];
  implementationNotes: string[];
};

export type TicketDraftErrorCode =
  | "codex_unavailable"
  | "codex_unauthenticated"
  | "timeout"
  | "cancelled"
  | "invalid_response"
  | "backend_failure";

export type TicketDraftErrorPayload = {
  code: TicketDraftErrorCode;
  message: string;
  recoverable: boolean;
  requestId: string;
  durationMs: number;
  reason: string;
  timeoutMs?: number;
};

export type TicketDraftResult =
  | {
      ok: true;
      draft: TicketDraft;
    }
  | {
      ok: false;
      error: TicketDraftErrorPayload;
    };

export type TicketCreateInput = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  markdown: string;
  status?: string;
};

export type TicketSaveInput = {
  projectPath: string;
  ticket: TicketRecord;
};

export type TicketMoveInput = {
  projectPath: string;
  ticketId: string;
  targetStatus: string;
  beforeTicketId?: string | null;
  afterTicketId?: string | null;
};

export type ClarificationAnswerType = "text";

export type ClarificationQuestion = {
  id: string;
  ticketId: string;
  question: string;
  answerType: ClarificationAnswerType;
  answer: string | null;
  createdAt: string;
  updatedAt: string;
  answeredAt: string | null;
  createdBy: RelayActor;
  source: RelayEventSource;
  runId: string | null;
  codexThreadId: string | null;
};

export type ClarificationQuestionCreateInput = {
  question: string;
  answerType?: ClarificationAnswerType;
};

export type ClarificationAnswerInput = {
  projectPath: string;
  ticketId: string;
  questionId: string;
  answer: string;
};

export type RelayAuditEvent = {
  schemaVersion: number;
  timestamp: string;
  actor: RelayActor;
  source: RelayEventSource;
  eventType: "ticket.status_changed" | "clarification.question_created" | "clarification.answer_submitted";
  ticketId?: string;
  runId?: string | null;
  payload: Record<string, unknown>;
};

export type AddProjectResult = {
  project: ProjectSummary;
  initialized: boolean;
};

export type AppRegistry = {
  schemaVersion: number;
  projects: Array<{
    path: string;
    pinned: boolean;
    lastOpenedAt: string;
    sidebarPosition: number;
  }>;
  ui: {
    lastProjectPath: string | null;
    theme: ThemePreference;
  };
};

export type RelayCodexEvent =
  | { type: "run.started"; runId: string; threadId: string; timestamp: string }
  | { type: "agent.message.delta"; text: string; timestamp: string }
  | { type: "agent.message.completed"; text: string; timestamp: string }
  | { type: "command.started"; command: string; cwd?: string; timestamp: string }
  | { type: "command.output"; stream: "stdout" | "stderr"; text: string; timestamp: string }
  | { type: "command.completed"; status: "completed" | "failed" | "declined"; timestamp: string }
  | { type: "file.change"; path: string; summary?: string; timestamp: string }
  | { type: "web.search"; query: string; timestamp: string }
  | { type: "approval.requested"; approvalId: string; kind: "command" | "file-change" | "network" | "other"; payload: unknown; timestamp: string }
  | { type: "approval.resolved"; approvalId: string; decision: string; timestamp: string }
  | { type: "ticket.status_changed"; fromStatus: string; toStatus: string; actor: RelayActor; source: RelayEventSource; timestamp: string }
  | { type: "clarification.requested"; questions: ClarificationQuestion[]; timestamp: string }
  | { type: "run.completed"; finalResponse: string; usage?: unknown; timestamp: string }
  | { type: "run.failed"; message: string; details?: unknown; timestamp: string };

export type RendererRunEvent = RelayCodexEvent & {
  projectPath: string;
  ticketId: string;
  runId: string;
};

export type RelayApprovalDecision = "accept" | "acceptForSession" | "decline" | "cancel";

export type CodexStatus = {
  sdkAvailable: boolean;
  cliAvailable: boolean;
  cliVersion: string | null;
  authenticated: boolean | null;
  message: string;
};

export type StartRunInput = {
  projectPath: string;
  ticketId: string;
  freshThread?: boolean;
};

export type CreateDraftInput = {
  projectPath: string;
  idea: string;

import { app, BrowserWindow, dialog, ipcMain, shell, type MessageBoxOptions, type OpenDialogOptions } from "electron";
import path from "node:path";
import { fileURLToPath } from "node:url";
import type {
  AddProjectResult,
  ClarificationAnswerInput,
  TicketCreateInput,
  TicketDraftResult,
  TicketMoveInput,
  TicketSaveInput
} from "../shared/types";
import {
  createTicketDraft,
  getCodexStatus,
  startCodexRun,
  resumeCodexRun,
  cancelCodexRun,
  approveCodexAction,
  readCodexRunEvents,
  ticketDraftErrorToPayload
} from "./services/codex";
import { getLogPath, logError, logInfo, logWarn } from "./services/logger";
import { readRegistry, removeProjectPath, upsertProjectPath } from "./services/registry";
import {
  createTicket,
  deleteTicket,
  duplicateTicket,
  answerClarificationQuestion,
  initializeProject,
  isTicketNotFoundError,
  moveTicket,
  readBoard,
  readClarificationQuestions,
  readTicket,
  revealTicketFile,
  saveTicket,
  summarizeProject,
} from "./services/storage";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

let mainWindow: BrowserWindow | null = null;

process.on("uncaughtException", (error) => {
  void logError("process", "uncaught exception", error);
});

process.on("unhandledRejection", (error) => {
  void logError("process", "unhandled rejection", error);
});

const createWindow = async (): Promise<void> => {
  mainWindow = new BrowserWindow({
    width: 1440,
    height: 980,
    minWidth: 1024,
    minHeight: 720,
    title: "Relay",
    backgroundColor: "#f6f4ef",
    show: false,
    webPreferences: {
      preload: path.join(__dirname, "../preload/index.mjs"),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: false
    }
  });

  mainWindow.once("ready-to-show", () => {
    mainWindow?.show();
  });

  mainWindow.webContents.on("render-process-gone", (_event, details) => {
    void logError("renderer", "render process gone", new Error(`${details.reason} (${details.exitCode})`));
  });

  mainWindow.webContents.on("did-fail-load", (_event, errorCode, errorDescription, validatedURL) => {
    void logError("renderer", "failed to load", new Error(`${errorCode} ${errorDescription} ${validatedURL}`));
  });

  if (process.env.ELECTRON_RENDERER_URL) {
    await mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
  } else {
    await mainWindow.loadFile(path.join(__dirname, "../renderer/index.html"));
  }
};

const registerIpc = (): void => {
  ipcMain.handle("projects:list", async () => {
    const registry = await readRegistry();
    return Promise.all(
      [...registry.projects]
        .sort((a, b) => a.sidebarPosition - b.sidebarPosition)
        .map((project) => summarizeProject(project.path, project.lastOpenedAt))
    );
  });

  ipcMain.handle("projects:addFolder", async (): Promise<AddProjectResult | null> => {
    const options: OpenDialogOptions = {
      title: "Add Relay Project",
      properties: ["openDirectory", "createDirectory"]
    };
    const result = mainWindow ? await dialog.showOpenDialog(mainWindow, options) : await dialog.showOpenDialog(options);
    if (result.canceled || result.filePaths.length === 0) return null;

    const projectPath = path.resolve(result.filePaths[0]);
    const summary = await summarizeProject(projectPath);
    let initialized = false;

    if (!summary.relayInitialized) {
      const messageBoxOptions: MessageBoxOptions = {
        type: "question",
        buttons: ["Initialize", "Cancel"],
        defaultId: 0,
        cancelId: 1,
        title: "Initialize Relay Project",
        message: "Relay needs to create a .relay folder in this project.",
        detail: projectPath
      };
      const confirm = mainWindow
        ? await dialog.showMessageBox(mainWindow, messageBoxOptions)
        : await dialog.showMessageBox(messageBoxOptions);
      if (confirm.response !== 0) return null;
      await initializeProject(projectPath);
      initialized = true;
    }

    await upsertProjectPath(projectPath);
    return {
      project: await summarizeProject(projectPath, new Date().toISOString()),
      initialized
    };
  });

  ipcMain.handle("projects:removeFromSidebar", async (_event, projectPath: string) => {
    const registry = await removeProjectPath(projectPath);
    return Promise.all(
      [...registry.projects]
        .sort((a, b) => a.sidebarPosition - b.sidebarPosition)
        .map((project) => summarizeProject(project.path, project.lastOpenedAt))
    );
  });

  ipcMain.handle("projects:read", async (_event, projectPath: string) => summarizeProject(projectPath));

  ipcMain.handle("projects:revealInFinder", async (_event, projectPath: string) => {
    await shell.openPath(projectPath);
  });

  ipcMain.handle("board:read", async (_event, projectPath: string) => readBoard(projectPath));

  ipcMain.handle("ticket:createDraft", async (_event, input): Promise<TicketDraftResult> => {
    try {
      return { ok: true, draft: await createTicketDraft(input) };
    } catch (error) {
      return { ok: false, error: ticketDraftErrorToPayload(error) };
    }
  });

  ipcMain.handle("ticket:createManual", async (_event, projectPath: string, input: TicketCreateInput) =>
    createTicket(projectPath, input)
  );

  ipcMain.handle("ticket:read", async (_event, projectPath: string, ticketId: string) => {
    const resolvedProjectPath = path.resolve(projectPath);
    try {
      return await readTicket(resolvedProjectPath, ticketId);
    } catch (error) {
      const meta = { projectPath: resolvedProjectPath, ticketId };
      if (isTicketNotFoundError(error)) {
        await logWarn("ticket:read", "ticket file missing", { ...meta, filePath: error.filePath });
      } else {
        await logError("ticket:read", "ticket read failed", error, meta);
      }
      throw error;
    }
  });

  ipcMain.handle("ticket:save", async (_event, input: TicketSaveInput) => saveTicket(input));

  ipcMain.handle("ticket:move", async (_event, input: TicketMoveInput) => moveTicket(input));

  ipcMain.handle("ticket:clarifications", async (_event, projectPath: string, ticketId: string) =>
    readClarificationQuestions(projectPath, ticketId)
  );

  ipcMain.handle("ticket:answerClarification", async (_event, input: ClarificationAnswerInput) =>
    answerClarificationQuestion(input.projectPath, input.ticketId, input.questionId, input.answer)
  );

  ipcMain.handle("ticket:delete", async (_event, projectPath: string, ticketId: string) => deleteTicket(projectPath, ticketId));

  ipcMain.handle("ticket:duplicate", async (_event, projectPath: string, ticketId: string) => duplicateTicket(projectPath, ticketId));

  ipcMain.handle("ticket:revealFile", async (_event, projectPath: string, ticketId: string) => revealTicketFile(projectPath, ticketId));

  ipcMain.handle("codex:status", async () => getCodexStatus());

  ipcMain.handle("codex:startRun", async (_event, input) => {
    if (!mainWindow) throw new Error("Relay window is not ready.");
    return startCodexRun(mainWindow, input);
  });

  ipcMain.handle("codex:resumeRun", async (_event, input) => {
    if (!mainWindow) throw new Error("Relay window is not ready.");
    return resumeCodexRun(mainWindow, input);
  });

  ipcMain.handle("codex:cancelRun", async (_event, runId: string) => cancelCodexRun(runId));

  ipcMain.handle("codex:approveAction", async (_event, approvalId: string, decision: string) => approveCodexAction(approvalId, decision));

  ipcMain.handle("codex:readRunEvents", async (_event, projectPath: string, ticketId: string, runId: string) =>
    readCodexRunEvents(projectPath, ticketId, runId)
  );
};

app.whenReady().then(async () => {
  await logInfo("app", "Relay starting", { logPath: getLogPath() });
  registerIpc();
  await createWindow();

  app.on("activate", async () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      await createWindow();
    }
  });
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") {
    app.quit();
  }
});

import { contextBridge, ipcRenderer } from "electron";
import type {
  ClarificationAnswerInput,
  CreateDraftInput,
  RelayApi,
  RelayApprovalDecision,
  RendererRunEvent,
  StartRunInput,
  TicketCreateInput,
  TicketMoveInput,
  TicketSaveInput
} from "../shared/types";

const api: RelayApi = {
  projects: {
    list: () => ipcRenderer.invoke("projects:list"),
    addFolder: () => ipcRenderer.invoke("projects:addFolder"),
    removeFromSidebar: (projectPath: string) => ipcRenderer.invoke("projects:removeFromSidebar", projectPath),
    read: (projectPath: string) => ipcRenderer.invoke("projects:read", projectPath),
    revealInFinder: (projectPath: string) => ipcRenderer.invoke("projects:revealInFinder", projectPath)
  },
  board: {
    read: (projectPath: string) => ipcRenderer.invoke("board:read", projectPath)
  },
  ticket: {
    createDraft: (input: CreateDraftInput) => ipcRenderer.invoke("ticket:createDraft", input),
    createManual: (projectPath: string, input: TicketCreateInput) => ipcRenderer.invoke("ticket:createManual", projectPath, input),
    read: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:read", projectPath, ticketId),
    save: (input: TicketSaveInput) => ipcRenderer.invoke("ticket:save", input),
    move: (input: TicketMoveInput) => ipcRenderer.invoke("ticket:move", input),
    clarifications: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:clarifications", projectPath, ticketId),
    answerClarification: (input: ClarificationAnswerInput) => ipcRenderer.invoke("ticket:answerClarification", input),
    delete: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:delete", projectPath, ticketId),
    duplicate: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:duplicate", projectPath, ticketId),
    revealFile: (projectPath: string, ticketId: string) => ipcRenderer.invoke("ticket:revealFile", projectPath, ticketId)
  },
  codex: {
    status: () => ipcRenderer.invoke("codex:status"),
    startRun: (input: StartRunInput) => ipcRenderer.invoke("codex:startRun", input),
    resumeRun: (input: StartRunInput) => ipcRenderer.invoke("codex:resumeRun", input),
    cancelRun: (runId: string) => ipcRenderer.invoke("codex:cancelRun", runId),
    approveAction: (approvalId: string, decision: RelayApprovalDecision) => ipcRenderer.invoke("codex:approveAction", approvalId, decision),
    readRunEvents: (projectPath: string, ticketId: string, runId: string) =>
      ipcRenderer.invoke("codex:readRunEvents", projectPath, ticketId, runId),
    onRunEvent: (listener: (event: RendererRunEvent) => void) => {
      const wrapped = (_event: Electron.IpcRendererEvent, payload: RendererRunEvent): void => listener(payload);
      ipcRenderer.on("codex:runEvent", wrapped);
      return () => ipcRenderer.removeListener("codex:runEvent", wrapped);
    }
  }
