const shortPath = (projectPath: string): string => {
  const parts = projectPath.split("/");
  if (parts.length <= 4) return projectPath;
  return `.../${parts.slice(-3).join("/")}`;
};

const runLabel = (status: TicketSummary["runStatus"]): string => {
  switch (status) {
    case "idle":
      return "Idle";
    case "running":
      return "Running";
    case "blocked":
      return "Blocked";
    case "failed":
      return "Failed";
    case "completed":
      return "Codex Done";
    case "cancelled":
      return "Cancelled";
    case "drafting":
      return "Drafting";
    default:
      return "Idle";
  }
};

