test("agent log viewer orders events chronologically and labels event types", () => {
  const markup = renderToStaticMarkup(
    <AgentLogViewer
      title="Ticket Logs"
      loading={false}
      error={null}
      events={[
        event({ type: "command.started", command: "npm test", timestamp: "2026-05-11T10:00:30.000Z" }),
